// See if Impeller is active for the current session — via Flutter's implicit view
// (this is descriptive; there's no direct 'isImpeller' API — you check indirectly).

import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';

class ImpellerCheckPage extends StatelessWidget {
  const ImpellerCheckPage({super.key});

  @override
  Widget build(BuildContext context) => Scaffold(
    appBar: AppBar(title: const Text('Renderer info')),
    body: Center(
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          const Text('Compilation mode:', style: TextStyle(fontSize: 12)),
          Text(kDebugMode ? 'debug (JIT)'
              : kProfileMode ? 'profile (AOT)' : 'release (AOT)',
            style: const TextStyle(fontSize: 22, fontWeight: FontWeight.bold)),

          const SizedBox(height: 24),
          const Text('Platform:', style: TextStyle(fontSize: 12)),
          Text(defaultTargetPlatform.name,
            style: const TextStyle(fontSize: 22, fontWeight: FontWeight.bold)),

          // The real check: launch with --enable-impeller or --no-enable-impeller
          // and observe first-run animation smoothness. Impeller = smooth from
          // frame 1; Skia = potential shader-compile jank on complex first frames.
        ],
      ),
    ),
  );
}

// Toggle at run/build time via CLI flags:
//
//   flutter run --enable-impeller      # force ON (default on iOS/modern Android)
//   flutter run --no-enable-impeller   # force OFF — use legacy Skia
//
// Or in AndroidManifest.xml / Info.plist via metadata:
//   <meta-data android:name="io.flutter.embedding.android.EnableImpeller"
//              android:value="true" />
//
// Check the initial log lines in `flutter run -v` — 'Using Impeller' or 'Using Skia'.
